from typing import List, Dict, Optional


def calculate_average_score(scores: List[float]) -> float:
    """Calculate the average of a list of scores."""
    total = sum(scores)
    return total / len(scores)


def find_longest_streak(values: List[bool]) -> int:
    """Find the longest consecutive streak of True values."""
    max_streak = 0
    current_streak = 0

    for value in values:
        if value:
            current_streak += 1
            max_streak = max(max_streak, current_streak)
        else:
            current_streak = 0

    return max_streak


def merge_user_profiles(profiles: List[Dict]) -> Dict:
    """Merge multiple user profile dicts into one combined profile."""
    merged = {}

    for profile in profiles:
        for key, value in profile.items():
            if key in merged and isinstance(merged[key], list):
                merged[key].extend(value if isinstance(value, list) else [value])
            else:
                merged[key] = value

    merged["profile_count"] = len(profiles)
    return merged

"""
A function that works correctly but has poor performance.
It can be optimized from O(n^2) to O(n).
"""

from typing import List, Tuple, Optional


def find_pair_with_sum(numbers: List[int], target: int) -> Optional[Tuple[int, int]]:
    """
    Find two numbers in the list that add up to the target sum.
    Returns a tuple of (index1, index2) or None if no pair exists.

    Current implementation: O(n^2) — checks every pair with nested loops.
    """
    if not numbers or len(numbers) < 2:
        return None

    for i in range(len(numbers)):
        for j in range(i + 1, len(numbers)):
            if numbers[i] + numbers[j] == target:
                return (i, j)

    return None


def find_duplicates(items: List[str]) -> List[str]:
    """
    Find all duplicate items in a list.
    Returns a list of items that appear more than once.

    Current implementation: O(n^2) — for each item, scans the whole list.
    """
    duplicates = []

    for i in range(len(items)):
        if items[i] in duplicates:
            continue
        count = 0
        for j in range(len(items)):
            if items[i] == items[j]:
                count += 1
        if count > 1:
            duplicates.append(items[i])

    return duplicates

"""
A recursive algorithm for analysis.
"""

from typing import List, Optional


def merge_sort(arr: List[int]) -> List[int]:
    """
    Sort an array using the merge sort algorithm.
    This is a recursive divide-and-conquer sorting algorithm.
    """
    if len(arr) <= 1:
        return arr

    mid = len(arr) // 2
    left_half = merge_sort(arr[:mid])
    right_half = merge_sort(arr[mid:])

    return _merge(left_half, right_half)


def _merge(left: List[int], right: List[int]) -> List[int]:
    """Merge two sorted arrays into one sorted array."""
    result = []
    i = j = 0

    while i < len(left) and j < len(right):
        if left[i] <= right[j]:
            result.append(left[i])
            i += 1
        else:
            result.append(right[j])
            j += 1

    result.extend(left[i:])
    result.extend(right[j:])
    return result


def binary_search(arr: List[int], target: int) -> Optional[int]:
    """
    Search for a target value in a sorted array using binary search.
    Returns the index of the target, or None if not found.
    """
    return _binary_search_recursive(arr, target, 0, len(arr) - 1)


def _binary_search_recursive(
    arr: List[int], target: int, low: int, high: int
) -> Optional[int]:
    """Recursive helper for binary search."""
    if low > high:
        return None

    mid = (low + high) // 2

    if arr[mid] == target:
        return mid
    elif arr[mid] < target:
        return _binary_search_recursive(arr, target, mid + 1, high)
    else:
        return _binary_search_recursive(arr, target, low, mid - 1)
